/*
 * sqrtf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly sqrtf  (test_sqrtf_opt.elf)
 *   2. Linked with toolchain's default sqrtf        (test_sqrtf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += sqrtf(vx);
#else
    float r = sqrtf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* 100 representative test points                                      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);                  /* +0.0 -> +0.0 */
    emit(-0.0f);                 /* -0.0 -> -0.0 (IEEE special case) */
    emit_u(0x7fc00000u);         /* qNaN -> qNaN */
    emit_u(0x7f800001u);         /* sNaN -> qNaN */
    emit_u(0xffc00000u);         /* -qNaN -> qNaN */
    emit_u(0x7f800000u);         /* +Inf -> +Inf */
    emit_u(0xff800000u);         /* -Inf -> NaN (domain error) */

    /* --- Section 2: Negative domain-error inputs (6) --- */
    emit_u(0x80000001u);         /* min negative subnormal -> NaN */
    emit_u(0x807fffffu);         /* max negative subnormal -> NaN */
    emit(-FLT_MIN);              /* -FLT_MIN = -2^-126 -> NaN */
    emit(-1.0f);                 /* -1.0 -> NaN */
    emit(-4.0f);                 /* -4.0 -> NaN */
    emit_u(0xff7fffffu);         /* -FLT_MAX -> NaN */

    /* --- Section 3: Positive subnormal inputs (6) --- */
    emit_u(0x00000001u);         /* min positive subnormal: 2^-149 */
    emit_u(0x00000002u);         /* 2^-148 */
    emit_u(0x00400000u);         /* mid subnormal: 2^-149 * 0x400000 */
    emit_u(0x00200000u);         /* lower-mid subnormal */
    emit_u(0x007ffffeu);         /* one ULP below max subnormal */
    emit_u(0x007fffffu);         /* max subnormal: just below FLT_MIN */

    /* --- Section 4: Normal boundary values (6) --- */
    emit(FLT_MIN);               /* 2^-126 = 0x00800000: smallest normal */
    emit_u(0x00800001u);         /* one ULP above FLT_MIN */
    emit_u(0x00800002u);         /* two ULPs above FLT_MIN */
    emit_u(0x7f7ffffeu);         /* one ULP below FLT_MAX */
    emit(FLT_MAX);               /* 0x7f7fffff: largest normal */
    emit_u(0x7f000000u);         /* 2^126: large but not max */

    /* --- Section 5: ULP neighbors of 1.0 (8) --- */
    emit_u(0x3f7ffffcu);         /* 4 ULPs below 1.0 */
    emit_u(0x3f7ffffeu);         /* 2 ULPs below 1.0 */
    emit_u(0x3f7fffffu);         /* 1 ULP below 1.0 */
    emit(1.0f);                  /* 1.0: sqrt = 1.0 exactly */
    emit_u(0x3f800001u);         /* 1 ULP above 1.0 */
    emit_u(0x3f800002u);         /* 2 ULPs above 1.0 */
    emit_u(0x3f800004u);         /* 4 ULPs above 1.0 */
    emit_u(0x3f800010u);         /* 16 ULPs above 1.0 */

    /* --- Section 6: Perfect squares with exact results (10) --- */
    emit(4.0f);                  /* sqrt(4) = 2 exactly */
    emit(9.0f);                  /* sqrt(9) = 3 exactly */
    emit(16.0f);                 /* sqrt(16) = 4 exactly */
    emit(25.0f);                 /* sqrt(25) = 5 exactly */
    emit(36.0f);                 /* sqrt(36) = 6 exactly */
    emit(49.0f);                 /* sqrt(49) = 7 exactly */
    emit(64.0f);                 /* sqrt(64) = 8 exactly */
    emit(100.0f);                /* sqrt(100) = 10 exactly */
    emit(0.25f);                 /* sqrt(0.25) = 0.5 exactly */
    emit(0.0625f);               /* sqrt(0.0625) = 0.25 exactly */

    /* --- Section 7: Irrational results / key mathematical values (8) --- */
    emit(2.0f);                  /* sqrt(2) = 1.41421..., irrational */
    emit(3.0f);                  /* sqrt(3) = 1.73205..., irrational */
    emit(5.0f);                  /* sqrt(5) = 2.23606..., irrational */
    emit(0.5f);                  /* sqrt(0.5) = 0.70710... */
    emit_u(0x40490fdbu);         /* pi = 3.14159..., sqrt(pi) irrational */
    emit_u(0x3fc90fdbu);         /* pi/2 = 1.5707..., sqrt(pi/2) irrational */
    emit_u(0x3f317218u);         /* ln2 = 0.6931..., sqrt(ln2) irrational */
    emit(7.0f);                  /* sqrt(7) = 2.64575..., irrational */

    /* --- Section 8: Exponent boundary values (12) --- */
    /* sqrt crosses integer exponent at inputs 2^(2k): result = 2^k */
    emit_u(0x3effffffu);         /* 1 ULP below 0.5 = 2^-1 */
    emit(0.5f);                  /* 0x3f000000: 2^-1, sqrt = 2^-0.5 */
    emit_u(0x3f000001u);         /* 1 ULP above 0.5 */
    emit_u(0x3fffffffu);         /* 1 ULP below 2.0 */
    emit(2.0f);                  /* 0x40000000: 2^1, sqrt crosses exponent */
    emit_u(0x40000001u);         /* 1 ULP above 2.0 */
    emit_u(0x407fffffu);         /* 1 ULP below 4.0 = 2^2, sqrt = 2 exactly */
    emit(4.0f);                  /* already in sec 6 but boundary matters here */
    emit_u(0x40800001u);         /* 1 ULP above 4.0 */
    emit_u(0x437fffffu);         /* 1 ULP below 256.0 = 2^8 */
    emit(256.0f);                /* sqrt(256) = 16 exactly */
    emit_u(0x43800001u);         /* 1 ULP above 256.0 */

    /* --- Section 9: Large inputs (9) --- */
    emit(1.0e6f);                /* sqrt ~ 1000 */
    emit(1.0e8f);                /* sqrt ~ 10000 */
    emit(1.0e10f);               /* sqrt ~ 100000 */
    emit(1.0e15f);               /* large: sqrt ~ 3.16e7 */
    emit(1.0e20f);               /* very large */
    emit(1.0e30f);               /* near FLT_MAX territory */
    emit_u(0x7e800000u);         /* 2^125: near FLT_MAX, sqrt = 2^62.5 */
    emit_u(0x7f000000u);         /* 2^126 */
    emit_u(0x7f600000u);         /* slightly below FLT_MAX */

    /* --- Section 10: ULP-hard cases near algorithmic boundaries (28) --- */
    /* Near 1.5: midpoint of [1, 2] primary interval */
    emit_u(0x3fbfffffu);         /* 1 ULP below 1.5 */
    emit(1.5f);                  /* 1.5 */
    emit_u(0x3fc00001u);         /* 1 ULP above 1.5 */

    /* Near 0.75: midpoint of [0.5, 1] */
    emit_u(0x3f3fffffu);         /* 1 ULP below 0.75 */
    emit(0.75f);                 /* 0.75 */
    emit_u(0x3f400001u);         /* 1 ULP above 0.75 */

    /* Near 3.0: midpoint of [2, 4] */
    emit_u(0x40400000u);         /* 3.0 - boundary in [2,4] */
    emit_u(0x403fffffu);         /* 1 ULP below 3.0 */
    emit_u(0x40400001u);         /* 1 ULP above 3.0 */

    /* Near 6.0: midpoint of [4, 8] */
    emit_u(0x40c00000u);         /* 6.0 */
    emit_u(0x40bfffffu);         /* 1 ULP below 6.0 */
    emit_u(0x40c00001u);         /* 1 ULP above 6.0 */

    /* Pythagorean triple members: known hard rounding cases */
    emit(144.0f);                /* sqrt(144) = 12 exactly */
    emit(169.0f);                /* sqrt(169) = 13 exactly */
    emit(225.0f);                /* sqrt(225) = 15 exactly */
    emit(625.0f);                /* sqrt(625) = 25 exactly */

    /* Irrational values near halfway points between consecutive floats */
    emit(2.0000001f);            /* just above 2: tests rounding direction */
    emit(3.0000001f);            /* just above 3 */
    emit(8.0f);                  /* 2^3: sqrt = 2*sqrt(2), irrational */
    emit(32.0f);                 /* 2^5: sqrt = 4*sqrt(2), irrational */
    emit(128.0f);                /* 2^7: sqrt = 8*sqrt(2), irrational */
    emit(512.0f);                /* 2^9: sqrt = 16*sqrt(2), irrational */
    emit(0.125f);                /* 2^-3: sqrt = sqrt(2)/4, irrational */
    emit(0.03125f);              /* 2^-5: sqrt = sqrt(2)/8, irrational */

    /* Small normals away from subnormal boundary */
    emit(1.0e-10f);              /* small but normal */
    emit(1.0e-20f);              /* very small normal */
    emit(1.0e-30f);              /* extremely small normal */
    emit_u(0x04000000u);         /* 2^-119: well into normal range */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 4] in 200 steps */
static void test_sweep(void)
{
    float hi = 4.0f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);
}

/* 8. Sample [0, 1] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
